import React from 'react';
import { Card, Stack, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function WeatherCard(props: Props): React.ReactElement {
  const {
    city,
    temperature,
    condition,
    humidity,
    windSpeed,
    unit = 'C',
    forecast,
  } = props;

  // Get weather emoji/icon based on condition
  const getWeatherIcon = (cond: string): string => {
    const condLower = cond.toLowerCase();
    if (condLower.includes('sunny') || condLower.includes('clear')) return '☀️';
    if (condLower.includes('cloudy') || condLower.includes('overcast')) return '☁️';
    if (condLower.includes('rainy') || condLower.includes('rain')) return '🌧️';
    if (condLower.includes('snowy') || condLower.includes('snow')) return '❄️';
    if (condLower.includes('storm') || condLower.includes('thunder')) return '⛈️';
    if (condLower.includes('partly')) return '⛅';
    return '🌤️';
  };

  const weatherIcon = getWeatherIcon(condition);

  return (
    <Card shadow="md" padding={24} radius="lg" border={true}>
      <Stack direction="vertical" gap={16}>
        {/* City name */}
        <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface, #18181b)">
          {city}
        </Text>

        {/* Current weather section with temperature and condition */}
        <Stack direction="horizontal" gap={12} align="center">
          <Text
            size="3xl"
            color="var(--ggui-color-onSurface, #18181b)"
            align="center"
          >
            {weatherIcon}
          </Text>
          <Stack direction="vertical" gap={4}>
            <Text
              size="4xl"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {temperature}°{unit}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {condition}
            </Text>
          </Stack>
        </Stack>

        {/* Humidity and Wind Speed section */}
        <Stack direction="horizontal" gap={16} justify="evenly">
          <Box
            padding={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius={8}
            style={{ flex: 1, textAlign: 'center' }}
          >
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Humidity
            </Text>
            <Text
              variant="bodySmall"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {humidity}%
            </Text>
          </Box>
          <Box
            padding={12}
            background="var(--ggui-color-surfaceVariant, #f4f4f5)"
            borderRadius={8}
            style={{ flex: 1, textAlign: 'center' }}
          >
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Wind Speed
            </Text>
            <Text
              variant="bodySmall"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {windSpeed} m/s
            </Text>
          </Box>
        </Stack>

        {/* Divider */}
        <Divider orientation="horizontal" margin={16} />

        {/* 5-day forecast strip */}
        <Stack
          direction="horizontal"
          gap={8}
          wrap={true}
          justify="evenly"
          align="center"
        >
          {forecast.map((forecastItem, index) => (
            <Box
              key={index}
              padding={8}
              background="var(--ggui-color-primary-50, #f0f9ff)"
              borderRadius={8}
              style={{
                flex: '0 1 calc(20% - 6.4px)',
                minWidth: '60px',
                textAlign: 'center',
              }}
            >
              <Stack direction="vertical" gap={4} align="center">
                {forecastItem.day && (
                  <Text
                    variant="caption"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {forecastItem.day}
                  </Text>
                )}
                {forecastItem.icon && (
                  <Text
                    size="lg"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {forecastItem.icon}
                  </Text>
                )}
                {forecastItem.high !== undefined && (
                  <Text
                    variant="bodySmall"
                    weight="medium"
                    color="var(--ggui-color-primary-700, #0369a1)"
                  >
                    {forecastItem.high}°
                  </Text>
                )}
                {forecastItem.low !== undefined && (
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {forecastItem.low}°
                  </Text>
                )}
              </Stack>
            </Box>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}
